<script>
function toggleDomain(header) {
  header.classList.toggle('collapsed');
  const table = header.parentElement.querySelector('.checklist-table');
  table.classList.toggle('hidden');
}

function applyFilters() {
  const prio   = document.getElementById('filterPrio').value;
  const domain = document.getElementById('filterDomain').value;
  const search = document.getElementById('searchBox').value.toLowerCase();

  document.querySelectorAll('.domain-section').forEach(section => {
    const sectionDomain = section.dataset.domain;
    let sectionVisible = false;

    section.querySelectorAll('tbody tr').forEach(row => {
      const rowDomain = row.dataset.domain || sectionDomain;
      const rowPrio   = row.dataset.prio   || '';
      const text      = row.textContent.toLowerCase();

      const domainOk = !domain || rowDomain === domain;
      const prioOk   = !prio   || rowPrio   === prio;
      const searchOk = !search || text.includes(search);

      const show = domainOk && prioOk && searchOk;
      row.style.display = show ? '' : 'none';
      if (show) sectionVisible = true;
    });

    section.style.display = sectionVisible ? '' : 'none';
  });
}
</script>
